-- 1) auth.users (bắt buộc trước vì profiles.id -> auth.users.id)
--    crypt() cần extension pgcrypto:
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- Trigger handle_new_user() sẽ tự tạo profile từ raw_user_meta_data (username/display_name).
-- Ta nhúng sẵn username + display_name thật vào metadata để tránh trùng username='' .
-- ON CONFLICT DO NOTHING (không cột) sẽ bỏ qua mọi vi phạm unique (id HOẶC email).


-- 1b) identities (chỉ chèn nếu auth.users có user đó - user mới được insert thành công)

-- 2) profiles (chỉ chèn nếu auth.users có user đó - tránh lỗi FK với email trùng)

-- 3) user_games (lookup game theo appid trong DB hiện tại - vì UUID giữa 2 DB khác nhau)

-- 4) owned_dlcs (base_appid/dlc_appid là TEXT, không có cột purchase_price_vnd)
